const data = $json;
const minScoreKey = data['Minimum Score'] || '';

const rawDate = data['Submission time'] || '';
let submissionDate = '';
if (rawDate) {
  const dt = new Date(rawDate);
  if (!isNaN(dt)) {
    submissionDate = dt.toLocaleDateString('en-US', {
      timeZone: 'America/New_York',
      year: 'numeric', month: '2-digit', day: '2-digit'
    });
  }
}

const improvementTitles = {
  'Lesson 1: Beware of Fat Plans': 'Focus on 3-7 priorities and ground them in reality',
  'Lesson 2: Build a Guiding Coalition and an Exceptional Team': 'To get to scale, it takes a village',
  "Lesson 3: Don't Wait!": 'Build routines & rituals into your systems',
  'Lesson 4: Be Consistent': 'Consistency is the secret to results'
};
const improvementHeaders = {
  'Lesson 1: Beware of Fat Plans': '✔ Lesson 1: Beware of Fat Plans',
  'Lesson 2: Build a Guiding Coalition and an Exceptional Team': '✔ Lesson 2: Build a Guiding Coalition and an Exceptional Team',
  "Lesson 3: Don't Wait!": "✔ Lesson 3: Don't Wait!",
  'Lesson 4: Be Consistent': '✔ Lesson 4: Be Consistent'
};
const lessonIndicatorKeys = {
  'Lesson 1: Beware of Fat Plans': [
    'Goals: Success in 1-3 years is clearly defined and measurable.',
    'Priorities: The top 3-7 priorities are identified and widely known.',
    'Alignment and Coherence: There is alignment and coherence amongst the priorities, evident in schools. Things that are in direct conflict are removed.'
  ],
  'Lesson 2: Build a Guiding Coalition and an Exceptional Team': [
    'Guiding Coalition: Key stakeholders of influence are engaged and meet periodically to inform and support implementation.',
    'Implementation Team: The right people with the requisite knowledge, skills, and relationships are leading project implementation.',
    'Delivery Chain: People in the field involved in implementation have the right mindset, guidance, capacity, and support to implement.'
  ],
  "Lesson 3: Don't Wait!": [
    'Feedback: Feedback loops are in place to capture what’s working and what’s not in implementation.',
    'Learning: Feedback and coaching is aimed at supporting growth and improvement (think carrots not sticks).',
    'Communication: Trusted messengers are used to communicate stories of impact to key stakeholders.'
  ],
  'Lesson 4: Be Consistent': [
    'Routines: Regular routines are held to drive implementation by celebrating and scaling what’s working and problem-solving areas that are off track.',
    'Time Blocking: Days and weeks are planned around the “big rocks” aligned with the priorities; other meetings and tasks are fit in around them.',
    'Consistency: There is a consistent drum beat of implementation focused on the priorities every day.'
  ]
};
const lessonChapter = {
  'Lesson 1: Beware of Fat Plans': 1,
  'Lesson 2: Build a Guiding Coalition and an Exceptional Team': 2,
  "Lesson 3: Don't Wait!": 3,
  'Lesson 4: Be Consistent': 4
};

const indicators = (lessonIndicatorKeys[minScoreKey] || []).map(k => '✔ ' + k).join('\n');
const chapter = lessonChapter[minScoreKey];
let improvementText = 'Indicators\n' + indicators;
if (chapter) {
  improvementText += '\n\nExplore this area of implementation further by:\n✔ Book: Read Chapter ' + chapter;
}

return [{ json: {
  ...data,
  pageId: data.id,
  submissionTime: rawDate,
  submissionDate,
  email: data['Email'] || '',
  firstName: data['First Name'] || '',
  lastName: data['Last Name'] || '',
  minScoreKey,
  improvementHeader: improvementHeaders[minScoreKey] || minScoreKey,
  improvementTitle: improvementTitles[minScoreKey] || '',
  improvementText,
  project: data['Project: Pick an implementation project to assess'] || '',
  scores: {
    L1: data['Lesson 1: Beware of Fat Plans'] || 0,
    L2: data['Lesson 2: Build a Guiding Coalition and an Exceptional Team'] || 0,
    L3: data["Lesson 3: Don't Wait!"] || 0,
    L4: data['Lesson 4: Be Consistent'] || 0,
    results: data['Results'] || 0,
    implementation: data['Implementation'] || 0,
    goals: data['1. Goals'] || 0,
    priorities: data['1. Priorities'] || 0,
    alignment: data['1. Alignment & Coherence'] || 0,
    coalition: data['2. Guiding Coalition'] || 0,
    implTeam: data['2. Implementation Team'] || 0,
    delivery: data['2. Delivery Chain'] || 0,
    feedback: data['3. Feedback'] || 0,
    learning: data['3. Learning'] || 0,
    communication: data['3. Communication'] || 0,
    routines: data['4. Routines'] || 0,
    timeBlocking: data['4. Time Blocking'] || 0,
    consistency: data['4. Consistency'] || 0,
    scorecard2x2: data['2x2 Results and Implementation'] || 0
  }
}}];

