parameters.jsCode:
const items = $input.all();
const data = $('Extract Assessment Data').item.json;
const dateStr = (data.submissionDate || '').replace(/\//g, '-');
const fileName = 'Scorecard Report | ' + (data.firstName || 'Respondent') + ' | ' + dateStr + '.pdf';
items.forEach(item => {
  if (item.binary && item.binary.data) {
    item.binary.data.fileName = fileName;
  }
});
return items;
